const output = $input.first().json.output;
const steps = JSON.parse(output);

let prompt = "A clean professional flowchart diagram showing an algorithm. White background, colorful rounded boxes, arrows between steps, modern flat design. Steps: ";

steps.forEach((step, i) => {
  prompt += `${i + 1}. ${step.title}. `;
});

return [{
  json: {
    prompt: prompt,
    chatId: $('Telegram Trigger').first().json.message.chat.id
  }
}];

const imageUrl = $input.first().json.data[0].url;
const chatId = $('Code in JavaScript').first().json.chatId;

// Görseli indir
const imgResponse = await helpers.httpRequest({
  method: 'GET',
  url: imageUrl,
  returnFullResponse: true,
  encoding: 'arraybuffer'
});

const base64 = Buffer.from(imgResponse.body).toString('base64');

// imgbb'ye yükle
const imgbbResponse = await helpers.httpRequest({
  method: 'POST',
  url: 'https://api.imgbb.com/1/upload',
  returnFullResponse: true,
  body: {
    key: 'your_key',
    image: base64
  },
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded'
  }
});

const publicUrl = imgbbResponse.body.data.url;

return [{
  json: {
    chatId: chatId,
    imageUrl: publicUrl
  }
}];
